package Full_Stack_ch3;

public class Multiplication {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		System.out.println("2nd Table");
		for(int i=1;i<=10;i++) {
			for(int j=2;j<=2;j++) {
				System.out.println(i + "*"+ j + "=" +(i*j));
			}
		}
		
		System.out.println();
		System.out.println("3rd Table");
		for(int i=1;i<=10;i++) {
			for(int j=3;j<=3;j++) {
				System.out.println(i + "*"+ j + "=" +(i*j));
			}
		}

		
		System.out.println();
		System.out.println("4th Table");
		for(int i=1;i<=10;i++) {
			for(int j=4;j<=4;j++) {
				System.out.println(i + "*"+ j + "=" +(i*j));
			}
		}

		System.out.println();
		System.out.println("5th Table");
		for(int i=1;i<=10;i++) {
			for(int j=5;j<=5;j++) {
				System.out.println(i + "*"+ j + "=" +(i*j));
			}
		}
		System.out.println();
	}

}
